/**
 * @fileoverview NodeBaseEditor view — DOM construction, rendering,
 * canvas / SVG drawing, minimap, context-menu chrome.
 *
 * Imports: constants, helpers (no dependency on state or events).
 *
 * @module module/NodeBaseEditor/view
 */

import razyui from '../../index.js';
import Icons from '../Icons.js';
import { SVG_NS, DEFAULTS, PART } from './constants.js';
import {
    portColor, mk, escHtml, bezier,
    getPortPos, getContentBounds,
} from './helpers.js';


// ══════════════════════════════════════════════════════════════════
//  Build DOM
// ══════════════════════════════════════════════════════════════════

/**
 * Construct the full editor DOM structure.
 * @param {Object} ctx - Context bridge.
 */
export function buildUI(ctx) {
    const el = ctx.el;
    el.addClass('node-base-editor nbe-root')
      .html('');
    PART.ROOT.apply(el);
    el.attr('tabindex', '0');

    // Toolbar
    ctx.toolbar = mk('div', 'nbe-toolbar');
    PART.TOOLBAR.apply(ctx.toolbar);

    // Helper to create a toolbar button
    const tbBtn = (action, title, icon, opts = {}) => {
        const btn = mk('button', 'nbe-tb-btn');
        if (opts.sm) btn.addClass('nbe-tb-sm');
        if (opts.active) btn.addClass('is-active');
        btn.attr({ 'data-action': action, title: title });
        PART.TB_BTN.apply(btn);
        if (opts.sm) PART.TB_SM.apply(btn);
        btn.html(icon);
        return btn;
    };
    const tbGroup = (...children) => {
        const g = mk('div', 'nbe-tb-group');
        PART.TB_GROUP.apply(g);
        children.forEach(c => g.append(c));
        return g;
    };
    const tbSep = () => {
        const s = mk('div', 'nbe-tb-sep');
        PART.TB_SEP.apply(s);
        return s;
    };

    const zoomLabel = mk('span', 'nbe-zoom-label');
    PART.ZOOM_LABEL.apply(zoomLabel);
    zoomLabel.text('100%');

    ctx.toolbar
        .append(tbGroup(
            tbBtn('undo', 'Undo (Ctrl+Z)', Icons.svg('rotate-ccw', { size: 16, strokeWidth: 1.8 })),
            tbBtn('redo', 'Redo (Ctrl+Y)', Icons.svg('rotate-cw', { size: 16, strokeWidth: 1.8 })),
        ))
        .append(tbSep())
        .append(tbGroup(
            tbBtn('zoom-out', 'Zoom out', Icons.svg('minus', { size: 14, strokeWidth: 2 }), { sm: true }),
            zoomLabel,
            tbBtn('zoom-in', 'Zoom in', Icons.svg('plus', { size: 14, strokeWidth: 2 }), { sm: true }),
            tbBtn('zoom-fit', 'Fit to view', Icons.svg('maximize-2', { size: 14, strokeWidth: 1.8 }), { sm: true }),
        ))
        .append(tbSep())
        .append(tbGroup(
            tbBtn('grid', 'Toggle grid', Icons.svg('grid', { size: 16, strokeWidth: 1.8 }), { active: ctx.showGrid }),
            tbBtn('minimap', 'Toggle mini-map', Icons.svg('sidebar', { size: 16, strokeWidth: 1.8 }), { active: ctx.config.showMinimap !== false }),
            tbBtn('group', 'Group selected (Ctrl+G)', Icons.svg('folder-plus', { size: 16, strokeWidth: 1.8 })),
        ));
    el.append(ctx.toolbar);

    // Node type panel (left sidebar)
    ctx.nodePanel = mk('div', 'nbe-node-panel');
    PART.NODE_PANEL.apply(ctx.nodePanel);
    if (!ctx.showPanel) ctx.nodePanel.addClass('is-hidden');

    // Body wrapper (panel + viewport)
    const body = mk('div', 'nbe-body');
    PART.BODY.apply(body);

    // Canvas wrapper
    const viewport = mk('div', 'nbe-viewport');
    PART.CANVAS.apply(viewport);
    ctx.canvas = mk('div', 'nbe-canvas').css('transformOrigin', '0 0');
    PART.CANVAS_INNER.apply(ctx.canvas);
    viewport.append(ctx.canvas).append(ctx.nodePanel);
    body.append(viewport);
    el.append(body);

    // Grid overlay (CSS driven)
    const gridOvl = mk('div', 'nbe-grid');
    PART.GRID.apply(gridOvl);
    if (ctx.showGrid) gridOvl.addClass('is-visible');
    gridOvl.css('backgroundSize', `${ctx.gridSize}px ${ctx.gridSize}px`);
    ctx.canvas.append(gridOvl);

    // SVG overlay for connections
    ctx.svg = razyui.el('svg', { class: 'nbe-svg', overflow: 'visible' });
    PART.SVG.apply(ctx.svg);
    ctx.canvas.append(ctx.svg);

    // Selection box
    ctx.selBoxEl = mk('div', 'nbe-sel-box');
    PART.SEL_BOX.apply(ctx.selBoxEl);
    ctx.selBoxEl.css('display', 'none');
    viewport.append(ctx.selBoxEl);

    // Context menu
    ctx.contextMenuEl = mk('div', 'nbe-ctx');
    PART.CTX.apply(ctx.contextMenuEl);
    ctx.contextMenuEl.css('display', 'none');
    el.append(ctx.contextMenuEl);

    // Mini-map
    ctx.minimapWrap = mk('div', 'nbe-minimap');
    PART.MINIMAP.apply(ctx.minimapWrap);
    if (ctx.config.showMinimap === false) ctx.minimapWrap.css('display', 'none');
    ctx.minimapCanvas = razyui.el('canvas', { width: 200, height: 140 });
    ctx.minimapWrap.append(ctx.minimapCanvas);
    el.append(ctx.minimapWrap);
    ctx.minimapCtx = ctx.minimapCanvas[0].getContext('2d');

    // Apply initial transform
    applyTransform(ctx);

    // Render node panel contents
    renderNodePanel(ctx);
}


// ══════════════════════════════════════════════════════════════════
//  Node-type panel
// ══════════════════════════════════════════════════════════════════

/**
 * Render the left node-type panel listing all registered node types.
 * @param {Object} ctx
 */
export function renderNodePanel(ctx) {
    const panel = ctx.nodePanel;
    panel.html('');
    const header = mk('div', 'nbe-np-header');
    PART.NP_HEADER.apply(header);
    header.text('Node Types');
    panel.append(header);

    // Group by category
    const categories = new Map();
    for (const [type, def] of ctx.nodeTypes) {
        const cat = def.category || 'General';
        if (!categories.has(cat)) categories.set(cat, []);
        categories.get(cat).push({ type, def });
    }

    for (const [cat, entries] of categories) {
        const catEl = mk('div', 'nbe-np-cat');
        PART.NP_CAT.apply(catEl);
        catEl.text(cat);
        panel.append(catEl);

        for (const { type, def } of entries) {
            const item = mk('div', 'nbe-np-item');
            PART.NP_ITEM.apply(item);
            item.data('nodeType', type);
            item.attr('draggable', 'true');

            const swatch = mk('span', 'nbe-np-swatch');
            PART.NP_SWATCH.apply(swatch);
            swatch.css('background-color', def.color || '#e0e0e0');
            const label = mk('span', 'nbe-np-label');
            PART.NP_LABEL.apply(label);
            label.text(`${def.icon || '●'} ${def.label || type}`);
            const info = mk('span', 'nbe-np-info');
            PART.NP_INFO.apply(info);
            const inC = (def.inputs || []).length;
            const outC = (def.outputs || []).length;
            info.text(`${inC} in / ${outC} out`);

            item.append(swatch).append(label).append(info);

            panel.append(item);
        }
    }

    if (ctx.nodeTypes.size === 0) {
        const empty = mk('div', 'nbe-np-empty');
        PART.NP_EMPTY.apply(empty);
        empty.text('No node types registered');
        panel.append(empty);
    }
}


// ══════════════════════════════════════════════════════════════════
//  Node rendering
// ══════════════════════════════════════════════════════════════════

/**
 * Create the DOM element for a node and append it to the canvas.
 * @param {Object} ctx
 * @param {Object} node - Internal node object.
 * @param {Object} [def] - Node type definition.
 */
export function renderNodeEl(ctx, node, def) {
    if (!def) def = ctx.nodeTypes.get(node.type) || {};
    const el = mk('div', 'nbe-node');
    PART.NODE.apply(el);
    el.data('nodeId', node.id)
      .css({ left: node.x + 'px', top: node.y + 'px' });

    // Header
    const header = mk('div', 'nbe-node-header');
    PART.NODE_HEADER.apply(header);
    header.css('background-color', def.color || '#e0e0e0');
    const iconSpan = mk('span', 'nbe-node-icon');
    PART.NODE_ICON.apply(iconSpan);
    iconSpan.html(def.icon || '●');
    const labelSpan = mk('span', 'nbe-node-label');
    PART.NODE_LABEL.apply(labelSpan);
    labelSpan.text(node.label);
    header.append(iconSpan).append(labelSpan);
    el.append(header);
    node.headerEl = header;

    // Body — two-column port layout
    const body = mk('div', 'nbe-node-body');
    PART.NODE_BODY.apply(body);
    const leftCol = mk('div', 'nbe-port-col nbe-port-left');
    PART.PORT_COL.apply(leftCol);
    PART.PORT_LEFT.apply(leftCol);
    const rightCol = mk('div', 'nbe-port-col nbe-port-right');
    PART.PORT_COL.apply(rightCol);
    PART.PORT_RIGHT.apply(rightCol);

    // Input ports
    const inputs = def.inputs || [];
    for (const pDef of inputs) {
        const row = mk('div', 'nbe-port is-input');
        PART.PORT.apply(row);
        row.data('portName', pDef.name);
        row.data('nodeId', node.id);
        const dot = mk('div', 'nbe-port-dot');
        PART.PORT_DOT.apply(dot);
        dot.css('background-color', portColor(pDef.type));
        dot.data('portName', pDef.name);
        dot.data('nodeId', node.id);
        dot.data('dir', 'input');
        dot.attr('title', `${pDef.name} (${pDef.type})`);
        const lbl = mk('span', 'nbe-port-label');
        PART.PORT_LABEL.apply(lbl);
        lbl.text(pDef.name);
        row.append(dot).append(lbl);
        leftCol.append(row);
        node.inputPorts.set(pDef.name, { name: pDef.name, type: pDef.type, el: row, dot, localX: 0, localY: 0 });
    }

    // Output ports
    const outputs = def.outputs || [];
    for (const pDef of outputs) {
        const row = mk('div', 'nbe-port is-output');
        PART.PORT.apply(row);
        row.data('portName', pDef.name);
        row.data('nodeId', node.id);
        const lbl = mk('span', 'nbe-port-label');
        PART.PORT_LABEL.apply(lbl);
        lbl.text(pDef.name);
        const dot = mk('div', 'nbe-port-dot');
        PART.PORT_DOT.apply(dot);
        dot.css('background-color', portColor(pDef.type));
        dot.data('portName', pDef.name);
        dot.data('nodeId', node.id);
        dot.data('dir', 'output');
        dot.attr('title', `${pDef.name} (${pDef.type})`);
        row.append(lbl).append(dot);
        rightCol.append(row);
        node.outputPorts.set(pDef.name, { name: pDef.name, type: pDef.type, el: row, dot, localX: 0, localY: 0 });
    }

    body.append(leftCol).append(rightCol);
    el.append(body);
    node.bodyEl = body;
    node.el = el;
    ctx.canvas.append(el);

    // Compute port offsets after layout settles
    requestAnimationFrame(() => updatePortOffsets(ctx, node));
}


// ══════════════════════════════════════════════════════════════════
//  Port offset calculation
// ══════════════════════════════════════════════════════════════════

/**
 * Recalculate the local (node-relative) offset of each port dot.
 * @param {Object} ctx
 * @param {Object} node
 */
export function updatePortOffsets(ctx, node) {
    if (!node.el) return;
    const nRect = node.el.getRect();
    const z = ctx.zoom || 1;
    const computeLocal = (dot) => {
        const dRect = dot.getRect();
        return {
            x: (dRect.left + dRect.width / 2 - nRect.left) / z,
            y: (dRect.top + dRect.height / 2 - nRect.top) / z,
        };
    };
    for (const p of node.inputPorts.values()) {
        const local = computeLocal(p.dot);
        p.localX = local.x;
        p.localY = local.y;
    }
    for (const p of node.outputPorts.values()) {
        const local = computeLocal(p.dot);
        p.localX = local.x;
        p.localY = local.y;
    }
    // Re-render any connections to/from this node
    updateConnectionsForNode(ctx, node.id);
}


// ══════════════════════════════════════════════════════════════════
//  Connection rendering
// ══════════════════════════════════════════════════════════════════

/**
 * Update the SVG path data for one connection.
 * @param {Object} ctx
 * @param {Object} conn
 */
export function updateConnectionPath(ctx, conn) {
    const p1 = getPortPos(ctx.nodes, conn.from.nodeId, conn.from.portId);
    const p2 = getPortPos(ctx.nodes, conn.to.nodeId, conn.to.portId);
    if (!p1 || !p2) return;
    const d = bezier(p1.x, p1.y, p2.x, p2.y);
    conn.path.attr('d', d);
    conn.hitPath.attr('d', d);
}

/**
 * Update all connections attached to a node.
 * @param {Object} ctx
 * @param {string} nodeId
 */
export function updateConnectionsForNode(ctx, nodeId) {
    for (const conn of ctx.connections.values()) {
        if (conn.from.nodeId === nodeId || conn.to.nodeId === nodeId) {
            updateConnectionPath(ctx, conn);
        }
    }
}

/**
 * Update every connection path.
 * @param {Object} ctx
 */
export function updateAllConnections(ctx) {
    for (const conn of ctx.connections.values()) updateConnectionPath(ctx, conn);
}


// ══════════════════════════════════════════════════════════════════
//  Transform
// ══════════════════════════════════════════════════════════════════

/**
 * Apply the current panX, panY and zoom as a CSS transform.
 * @param {Object} ctx
 */
export function applyTransform(ctx) {
    ctx.canvas.css('transform', `translate(${ctx.panX}px, ${ctx.panY}px) scale(${ctx.zoom})`);
    const label = ctx.el.find('.nbe-zoom-label');
    if (label.length) label.text(Math.round(ctx.zoom * 100) + '%');
    scheduleMinimapRender(ctx);
}


// ══════════════════════════════════════════════════════════════════
//  Mini-map
// ══════════════════════════════════════════════════════════════════

/**
 * Schedule a minimap render on the next animation frame.
 * @param {Object} ctx
 */
export function scheduleMinimapRender(ctx) {
    if (ctx.mmRaf) return;
    ctx.mmRaf = requestAnimationFrame(() => {
        ctx.mmRaf = 0;
        renderMinimap(ctx);
    });
}

/**
 * Render the minimap.
 * @param {Object} ctx
 */
export function renderMinimap(ctx) {
    if (ctx.minimapWrap.css('display') === 'none') return;
    const mCtx = ctx.minimapCtx;
    const cw = ctx.minimapCanvas[0].width;
    const ch = ctx.minimapCanvas[0].height;
    mCtx.clearRect(0, 0, cw, ch);

    // Content bounds
    const bounds = getContentBounds(ctx.nodes, ctx.groups);
    if (!bounds) return;
    const pad = 40;
    const bw = bounds.w + pad * 2;
    const bh = bounds.h + pad * 2;
    const scale = Math.min(cw / bw, ch / bh);
    const ox = (cw - bw * scale) / 2 - (bounds.x - pad) * scale;
    const oy = (ch - bh * scale) / 2 - (bounds.y - pad) * scale;

    // Groups
    for (const g of ctx.groups.values()) {
        mCtx.fillStyle = (g.color || '#ccc') + '44';
        mCtx.strokeStyle = g.color || '#ccc';
        mCtx.lineWidth = 1;
        mCtx.fillRect(g.x * scale + ox, g.y * scale + oy, g.width * scale, g.height * scale);
        mCtx.strokeRect(g.x * scale + ox, g.y * scale + oy, g.width * scale, g.height * scale);
    }

    // Connections
    mCtx.strokeStyle = '#888';
    mCtx.lineWidth = 1;
    for (const conn of ctx.connections.values()) {
        const p1 = getPortPos(ctx.nodes, conn.from.nodeId, conn.from.portId);
        const p2 = getPortPos(ctx.nodes, conn.to.nodeId, conn.to.portId);
        if (p1 && p2) {
            mCtx.beginPath();
            mCtx.moveTo(p1.x * scale + ox, p1.y * scale + oy);
            mCtx.lineTo(p2.x * scale + ox, p2.y * scale + oy);
            mCtx.stroke();
        }
    }

    // Nodes
    for (const node of ctx.nodes.values()) {
        const def = ctx.nodeTypes.get(node.type);
        mCtx.fillStyle = def?.color || '#ddd';
        const nw = (node.el?.prop('offsetWidth') || DEFAULTS.nodeFallbackW);
        const nh = (node.el?.prop('offsetHeight') || DEFAULTS.nodeFallbackH);
        mCtx.fillRect(node.x * scale + ox, node.y * scale + oy, nw * scale, nh * scale);
    }

    // Viewport rectangle
    const vp = ctx.el.find('.nbe-viewport');
    if (vp.length) {
        const vr = vp.getRect();
        const vpX = (-ctx.panX / ctx.zoom) * scale + ox;
        const vpY = (-ctx.panY / ctx.zoom) * scale + oy;
        const vpW = (vr.width / ctx.zoom) * scale;
        const vpH = (vr.height / ctx.zoom) * scale;
        mCtx.strokeStyle = 'hsl(216, 72%, 56%)';
        mCtx.lineWidth = 2;
        mCtx.strokeRect(vpX, vpY, vpW, vpH);
    }
}


// ══════════════════════════════════════════════════════════════════
//  Context menu chrome
// ══════════════════════════════════════════════════════════════════

/**
 * Render context menu items at mouse position.
 * @param {Object} ctx
 * @param {Array} items
 * @param {MouseEvent} e
 */
export function renderContextMenu(ctx, items, e) {
    const menu = ctx.contextMenuEl;
    menu.html('');
    for (const item of items) {
        if (item.type === 'header') {
            const h = mk('div', 'nbe-ctx-header');
            PART.CTX_HEADER.apply(h);
            h.text(item.label);
            menu.append(h);
        } else if (item.type === 'sep') {
            const sep = mk('div', 'nbe-ctx-sep');
            PART.CTX_SEP.apply(sep);
            menu.append(sep);
        } else {
            const row = mk('div', 'nbe-ctx-item');
            PART.CTX_ITEM.apply(row);
            row.html(item.label);
            row[0]._action = item.action;
            menu.append(row);
        }
    }
    // Position
    const elRect = ctx.el.getRect();
    let left = e.clientX - elRect.left;
    let top = e.clientY - elRect.top;
    menu.css('display', 'block');
    // Clamp to container bounds
    requestAnimationFrame(() => {
        const mw = menu.prop('offsetWidth');
        const mh = menu.prop('offsetHeight');
        if (left + mw > elRect.width) left = elRect.width - mw - 4;
        if (top + mh > elRect.height) top = elRect.height - mh - 4;
        menu.css({ left: Math.max(0, left) + 'px', top: Math.max(0, top) + 'px' });
    });
    menu.css({ left: left + 'px', top: top + 'px' });
}

/**
 * Hide the context menu.
 * @param {Object} ctx
 */
export function hideContextMenu(ctx) {
    ctx.contextMenuEl.css('display', 'none');
}


// ══════════════════════════════════════════════════════════════════
//  Wire drag preview
// ══════════════════════════════════════════════════════════════════

/**
 * Create the temporary SVG path for wire drag preview.
 * @param {Object} ctx
 */
export function createTempWire(ctx) {
    const path = razyui.el('path', {
        class: 'nbe-wire-preview', fill: 'none',
        'stroke-dasharray': '6 4', 'stroke-width': '2', 'pointer-events': 'none',
    });
    PART.WIRE_PREVIEW.apply(path);
    // Color from source port
    const node = ctx.nodes.get(ctx.wireDrag.fromNodeId);
    const port = ctx.wireDrag.isOutput
        ? node?.outputPorts.get(ctx.wireDrag.fromPortId)
        : node?.inputPorts.get(ctx.wireDrag.fromPortId);
    path.attr('stroke', portColor(port?.type || 'any'));
    ctx.svg.append(path);
    ctx.wireDrag.tempPath = path;
}
